prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?startName (COUNT(DISTINCT ?task) AS ?taskCount) (COUNT(DISTINCT ?unreachable) AS ?unreachableCount) WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "1c273a0818b146269ac04f6b8d518698" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  OPTIONAL {
    FILTER NOT EXISTS {
      ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?taskReachable .
      FILTER(?taskReachable = ?task)
    }
    BIND(?task AS ?unreachable)
  }
}
GROUP BY ?choreo ?startName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoId ?start ?startName ?taskCount WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "1c273a0818b146269ac04f6b8d518698" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  OPTIONAL { ?choreo bbo:name ?choreoId . }

  ?start a bboExt:StartEvent .
  ?start tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  {
    SELECT (COUNT(DISTINCT ?task) AS ?taskCount) WHERE {
      ?task a bboExt:ChoreographyTask .
      ?task tai:belongsTo ?choreo .
    }
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?normId ?origId ?created ?orgId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL {
    ?model tai:belongsTo ?org .
    ?org tai:organizationId ?orgId .
  }
  FILTER(
    (BOUND(?normId) && STR(?normId) = "1c273a0818b146269ac04f6b8d518698") ||
    (BOUND(?origId) && STR(?origId) = "1c273a0818b146269ac04f6b8d518698")
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?start ?startName ?task ?taskName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "1c273a0818b146269ac04f6b8d518698" .

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo .
  OPTIONAL { ?start bbo:name ?startName . }

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  FILTER NOT EXISTS {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?taskReachable .
    FILTER(?taskReachable = ?task)
  }
  OPTIONAL { ?task bbo:name ?taskName . }
}
LIMIT 25
